    @classmethod
    def is_replay(cls, response_id):
        """Check if this response ID has been seen before."""
        if not response_id:
            return True
        return cls.objects.filter(response_id=response_id).exists()

    @classmethod
    def record_response(cls, response_id, issuer=''):
        """Record a processed response ID."""
