        if current_depth > cls.MAX_DEPTH:
            raise SAMLValidationError(
                f"XML tree exceeds maximum allowed depth of {cls.MAX_DEPTH}"
            )
        for child in element:
            cls._check_depth(child, current_depth + 1)

