class SAMLResponseParser:
    """Parses SAML Response XML and extracts user information."""

    def __init__(self, xml_root):
        self.root = xml_root
        self.assertion = xml_root.find('.//saml:Assertion', SAML_NAMESPACES)

    def get_response_id(self):
        """Extract the Response ID."""
        return self.root.get('ID', '')

    def get_name_id(self):
        """Extract the NameID from the assertion Subject."""
        if self.assertion is None:
            return None

        name_id_elem = self.assertion.find(
            'saml:Subject/saml:NameID', SAML_NAMESPACES
        )
        if name_id_elem is not None and name_id_elem.text:
            return name_id_elem.text.strip()
        return None

    def get_name_id_format(self):
        """Extract the NameID format."""
        if self.assertion is None:
            return None

        name_id_elem = self.assertion.find(
            'saml:Subject/saml:NameID', SAML_NAMESPACES
        )
        if name_id_elem is not None:
            return name_id_elem.get('Format', '')
        return None

    def get_session_index(self):
        """Extract the SessionIndex from AuthnStatement."""
        if self.assertion is None:
            return None

        authn_statement = self.assertion.find(
            'saml:AuthnStatement', SAML_NAMESPACES
        )
        if authn_statement is not None:
            return authn_statement.get('SessionIndex', '')
        return None

    def get_attributes(self):
        """Extract all attributes from the assertion's AttributeStatement."""
        attributes = {}
        if self.assertion is None:
            return attributes

        attr_statement = self.assertion.find(
            'saml:AttributeStatement', SAML_NAMESPACES
        )
        if attr_statement is None:
            return attributes

        for attr_elem in attr_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attr_elem.get('Name', '')
            if not attr_name:
                continue

            values = []
            for value_elem in attr_elem.findall(
                'saml:AttributeValue', SAML_NAMESPACES
            ):
                if value_elem.text:
                    values.append(value_elem.text.strip())

            if values:
                attributes[attr_name] = values

        return attributes

    def get_mapped_attributes(self):
        """Map SAML attributes to Django user fields using the attribute map."""
        raw_attributes = self.get_attributes()
        attribute_map = get_saml_setting('SAML_ATTRIBUTE_MAP')
        mapped = {}

        for django_field, saml_attr_names in attribute_map.items():
            for saml_attr_name in saml_attr_names:
                if saml_attr_name in raw_attributes:
                    values = raw_attributes[saml_attr_name]
                    # Take the first value for single-valued fields
                    mapped[django_field] = values[0] if len(values) == 1 else values
                    break

        return mapped

    def get_issuer(self):
        """Extract the Issuer from the response."""
        issuer_elem = self.root.find('saml:Issuer', SAML_NAMESPACES)
        if issuer_elem is not None and issuer_elem.text:
            return issuer_elem.text.strip()
        return None


class SAMLUserManager:
    """Manages Django user creation and updates from SAML data."""

    @staticmethod
    def sanitize_username(raw_username):
        """Sanitize username to prevent injection and ensure validity."""
        if not raw_username:
            return None

        # Strip whitespace
        username = raw_username.strip()

        # Limit length
        username = username[:150]

        # Remove potentially dangerous characters
        import re
        username = re.sub(r'[^\w.@+-]', '', username)

        if not username:
            return None

        return username

    @staticmethod
    def sanitize_field(value, max_length=150):
        """Sanitize a user field value."""
        if not value:
            return ''
        if isinstance(value, list):
            value = value[0] if value else ''
        return str(value).strip()[:max_length]

    @classmethod
    def get_or_create_user(cls, name_id, mapped_attributes):
        """
        Get or create a Django user based on SAML NameID and attributes.
        Returns (user, created) tuple.
        """
        if not name_id:
            raise SAMLValidationError("Cannot create user session without NameID")

        # Determine username
        username = cls.sanitize_username(
            mapped_attributes.get('username', name_id)
        )
        if not username:
            username = cls.sanitize_username(name_id)
        if not username:
            raise SAMLValidationError("Could not derive a valid username from SAML data")

        email = cls.sanitize_field(
            mapped_attributes.get('email', ''), max_length=254
        )
        first_name = cls.sanitize_field(
            mapped_attributes.get('first_name', ''), max_length=150
        )
        last_name = cls.sanitize_field(
            mapped_attributes.get('last_name', ''), max_length=150
        )

        create_unknown = get_saml_setting('SAML_CREATE_UNKNOWN_USER')

        try:
            user = User.objects.get(username=username)
            created = False

            # Update user attributes
            updated = False
            if email and user.email != email:
                user.email = email
                updated = True
            if first_name and user.first_name != first_name:
                user.first_name = first_name
                updated = True
            if last_name and user.last_name != last_name:
                user.last_name = last_name
                updated = True

            if updated:
                user.save(update_fields=['email', 'first_name', 'last_name'])
                logger.info(f"Updated user attributes for: {username}")

        except User.DoesNotExist:
            if not create_unknown:
                raise SAMLValidationError(
                    f"User '{username}' does not exist and SAML_CREATE_UNKNOWN_USER is False"
                )

            user = User.objects.create_user(
                username=username,
                email=email,
                first_name=first_name,
                last_name=last_name,
            )
            # Set unusable password - user authenticates via SAML only
            user.set_unusable_password()
            user.save()
            created = True
            logger.info(f"Created new user from SAML: {username}")

        return user, created


@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """
    Assertion Consumer Service (ACS) endpoint.
    Handles SAML POST responses from the Identity Provider.
    """

    def post(self, request):
        """Process SAML POST response."""
        try:
            # Extract SAMLResponse from POST data
            saml_response_b64 = request.POST.get('SAMLResponse')
            if not saml_response_b64:
                logger.warning("No SAMLResponse in POST data")
                return HttpResponseBadRequest("Missing SAMLResponse parameter")

            relay_state = request.POST.get('RelayState', '')

            # Decode the SAML response
            xml_bytes = self._decode_saml_response(saml_response_b64)

            # Validate XML size
            SAMLXMLValidator.validate_xml_size(xml_bytes)

            # Safely parse XML
            root = SAMLXMLValidator.safe_parse_xml(xml_bytes)

            # Validate XML structure
            SAMLXMLValidator.validate_structure(root)

            # Validate issuer
            SAMLXMLValidator.validate_issuer(root)

            # Validate timestamps
            SAMLXMLValidator.validate_timestamps(root)

            # Validate audience
            SAMLXMLValidator.validate_audience(root)

            # Parse the response
            parser = SAMLResponseParser(root)

            # Check for replay attacks
            response_id = parser.get_response_id()
            if SAMLResponseStore.is_replay(response_id):
                logger.warning(f"Replay attack detected for response ID: {response_id}")
                return HttpResponseForbidden("SAML Response replay detected")

            # Extract user information
            name_id = parser.get_name_id()
            if not name_id:
                raise SAMLValidationError("No NameID found in SAML assertion")

            mapped_attributes = parser.get_mapped_attributes()
            session_index = parser.get_session_index()

            logger.info(
                f"Processing SAML response for NameID: {name_id}, "
                f"Issuer: {parser.get_issuer()}"
            )

            # Get or create user
            user, created = SAMLUserManager.get_or_create_user(
                name_id, mapped_attributes
            )

            # Record the response to prevent replay
            SAMLResponseStore.record_response(
                response_id, issuer=parser.get_issuer() or ''
            )

            # Create Django session
            login(request, user, backend='django.contrib.auth.backends.ModelBackend')

            # Store SAML-specific data in session
            request.session['saml_name_id'] = name_id
            request.session['saml_name_id_format'] = parser.get_name_id_format() or ''
            request.session['saml_session_index'] = session_index or ''
            request.session['saml_issuer'] = parser.get_issuer() or ''
            request.session['saml_attributes'] = mapped_attributes

            # Regenerate session key for security
            request.session.cycle_key()

            logger.info(
                f"SAML login successful for user: {user.username} "
                f"(created: {created})"
            )

            # Determine redirect URL
            redirect_url = self._get_safe_redirect_url(relay_state)
            return HttpResponseRedirect(redirect_url)

        except SAMLValidationError as e:
            logger.error(f"SAML validation error: {e}")
            return HttpResponseBadRequest(f"SAML validation failed: {e}")
        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {e}")
            return HttpResponseBadRequest("Error processing SAML response")

    def _decode_saml_response(self, saml_response_b64):
        """Decode base64-encoded SAML response."""
        try:
            # Clean up the base64 string
            saml_response_b64 = saml_response_b64.strip()
            xml_bytes = base64.b64decode(saml_response_b64)
            return xml_bytes
        except Exception as e:
            raise SAMLValidationError(f"Failed to decode SAML response: {e}")

    def _get_safe_redirect_url(self, relay_state):
        """Validate and return a safe redirect URL."""
        default_url = get_saml_setting('SAML_DEFAULT_REDIRECT_URL')

        if not relay_state:
            return default_url

        # Only allow relative URLs or URLs to our own domain
        from urllib.parse import urlparse
        parsed = urlparse(relay_state)

        # Allow relative URLs
        if not parsed.scheme and not parsed.netloc:
            # Ensure it starts with /
            if relay_state.startswith('/'):
                return relay_state
            return default_url

        # Allow URLs to our own domain
        allowed_hosts = getattr(settings, 'ALLOWED_HOSTS', [])
        if parsed.netloc in allowed_hosts and parsed.scheme in ('http', 'https'):
            return relay_state

        logger.warning(f"Rejected unsafe redirect URL: {relay_state}")
        return default_url


class SAMLLoginView(View):
    """Initiates SAML authentication by redirecting to the IdP."""

    def get(self, request):
        """Generate SAML AuthnRequest and redirect to IdP."""
        idp_sso_url = get_saml_setting('SAML_IDP_SSO_URL')
        if not idp_sso_url:
            return HttpResponseBadRequest("SAML IdP SSO URL not configured")

        entity_id = get_saml_setting('SAML_ENTITY_ID')
        acs_url = get_saml_setting('SAML_ACS_URL')
        request_id = f"_{''.join(secrets.token_hex(16))}"
        issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')

        authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

        # Encode for HTTP-Redirect binding
        compressed = zlib.compress(authn_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')

        from urllib.parse import urlencode, quote_plus
        relay_state = request.GET.get('next', get_saml_setting('SAML_DEFAULT_REDIRECT_URL'))

        params = {
            'SAMLRequest': encoded,
        }
        if relay_state:
            params['RelayState'] = relay_state

        redirect_url = f"{idp_sso_url}?{urlencode(params)}"

        # Store request ID in session for validation
        request.session['saml_request_id'] = request_id

        return HttpResponseRedirect(redirect_url)


